public abstract class BasePublisher {
  protected void publish(Object event) {
    for (Listener listener : listeners) listener.onEvent(event);
  }
}

public final class OrderService extends BasePublisher {
  public void submit(Order order) { publish(new OrderSubmitted(order.id())); }
}

public final class OrderRepository {
  public void save(Order order) { database.insert(order); }
}

export async function runWithRetry(job: () => Promise<void>) {
  for (let attempt = 0; attempt < 3; attempt += 1) {
    try { await job(); return; } catch (error) { if (attempt === 2) throw error; }
  }
}

type State int
const ( Closed State = iota; Open )
type Breaker struct { state State; successes int }
func (b *Breaker) OnFailure() { b.state = Open; b.successes = 0 }
func (b *Breaker) OnSuccess() { if b.state == Open { b.successes++ } }
func (b *Breaker) Allow() bool { return b.state == Closed }

class NotificationService:
    def __init__(self, queue, repository):
        self.queue = queue
        self.repository = repository
    def send_now(self, message):
        self.repository.record(message)
        self.queue.publish(message)

class DeliveryScheduler:
    def __init__(self, clock, notifications):
        self.clock = clock
        self.notifications = notifications
    def tick(self):
        for message in self.clock.due_messages():
            self.notifications.send_now(message)

class ImportController:
    def __init__(self, job): self.job = job
    async def start(self, source): return await self.job.run(source)

def register(request, service):
